export function getNevadaHormoneClinicsByCity(citySlug: string): HormoneClinic[] {
  return nevadaHormoneClinics.filter(c => c.citySlug === citySlug);
}

export function getNevadaHormoneCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of nevadaHormoneClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
